```class Solution {
public:
    int maxSatisfied(vector<int>& customers, vector<int>& grumpy, int minutes) {
        int total = 0, maxIncrease = 0, window = 0;
        for (int i = 0; i < customers.size(); i++) {
            if (!grumpy[i]) total += customers[i];
            if (i < minutes) window += grumpy[i] ? customers[i] : 0;
            else window = window - (grumpy[i - minutes] ? customers[i - minutes] : 0) + (grumpy[i] ? customers[i] : 0);
            maxIncrease = max(maxIncrease, window);
        }
        return total + maxIncrease;
    }
};
